import axios from 'axios'
import React, { useEffect, useState } from 'react'

export default function ViewEmployee() {

  const [employees, setEmployees] = useState([])

    let[handleprofile, sethandleprofile]=useState("");

  let [showform, setshowform] = useState(false)
  let [profile, setProfile] = useState("");
    let [firstname, setfirstname] = useState("");
    let [lastname, setlastname] = useState("");
    let [middlename, setmiddlename] = useState("");
    let [email, setemail] = useState("");
    let [contactno, setcontactno] = useState(0);
    let [gender, setgender] = useState("");
    let [dob ,setdob] = useState("");
    let [caddress, setcaddress] = useState("");
    let [paddress, setpaddress] = useState("");
    let [adharno ,setadharno] = useState(0);
    let [edu, setedu] = useState("");
    let[panno, setpanno] = useState("");
    let[exp, setexp] = useState("");
    let[salary, setsalary] = useState("");
    let[designation, setdesignation] = useState("");
    let [department, setdepartment] = useState("");
    let [reportingmanager, setreportingmanager] = useState("");
    let [worklocation ,setworklocation] = useState("");
    let [status, setstatus] = useState("");
    let [joiningdate, setjoiningdate] = useState("");

    let[empid,setempid] = useState("");
    let[reload, setreload]=useState(false);

    //for searching
    let[searchby, setsearchby]=useState("");
    let[keyword, setkeyword]=useState("");
    let[searchResult, setsearchResult]=useState([]);



  useEffect(()=>{
    axios.get("http://localhost:8080/findallemp")
      .then((response)=>{
        setEmployees(response.data);
      })
      .catch(()=>{
        alert("Error in fetching data")
      })
  },[])

  //delete
  const deleteEmployee = (id)=>{
    axios.delete(`http://localhost:8080/deleteemp/${id}`)
    .then((response)=>{
        if(response.data=="Employee Deleted Successfully"){
            alert(response.data)
        }
    })
    .catch((error)=>{
        alert("Error deleting employee")
    })
  }

  //update
  let readytoupdate=(emp)=>{
    setshowform(true);
    setfirstname(emp.firstname);
    setmiddlename(emp.middlename)
    setlastname(emp.lastname)
    setemail(emp.email)
    setcontactno(emp.contactno)
    setgender(emp.gender)
    setdob(emp.dob)
    setcaddress(emp.caddress)
    setpaddress(emp.paddress)
    setadharno(emp.adharno)
    setpanno(emp.panno)
    setexp(emp.exp)
    setsalary(emp.salary)
    setedu(emp.edu)
    setdesignation(emp.designation)
    setdepartment(emp.department)
    setworklocation(emp.worklocation)
    setreportingmanager(emp.reportingmanager)
    setstatus(emp.status)
    setjoiningdate(emp.joiningdate)

    setempid(emp.empid)
  }


  //update
  let updateemployee=(emp)=>{

    emp.preventDefault();
    //empid
    let newemp = {firstname,lastname,middlename,dob,gender,caddress,paddress,adharno,
            panno,profile,email,contactno,designation,department,salary,reportingmanager,exp,
            worklocation,status,joiningdate,edu
        }

    axios.put(`http://localhost:8080/updateemp?empid=${empid}`, newemp)
    .then((response)=>{
        if(response.data=="Employee Updated Successfully"){
            alert(response.data);
        }
    })
    .catch((error)=>{
         alert("Error in updating employee")
    })
  }

  return (
    <div className='maindiv'>

        //for seraching employee record by specific element
        <div>
            Select searchby:
            <select onChange={(event)=>{setsearchby(event.target.value)}}>
                <option>Search Employee</option>
                <option value={firstname}>By FirstName</option>
                <option value={lastname}>By LastName</option>
                <option value={department}>By Department</option>
                <option value={designation}>By Designation</option>
                <option value={empid}>By EmpID</option>
            </select>
            {
                searchby && <input></input>}
            }
        </div>



    <div className="container-fluid">

      <div className="row">

      {employees.map((emp)=>(
        
        <div className="col-md-4 mb-2" key={emp.id}>

          <div className="card" style={{width:"18rem"}}>

            <img src={emp.profile} className="card-img-top" alt="profile"/>

            <div className="card-body">

              <h5 className="card-title">
                {emp.firstname} {emp.middlename} {emp.lastname}
              </h5>

              <div>
                <p>Contact No: <strong>{emp.contactno}</strong></p>
                <p>Email: <strong>{emp.email}</strong></p>
                <p>Department: <strong>{emp.department}</strong></p>
                <p>Designation: <strong>{emp.designation}</strong></p>
                <p>Work Location: <strong>{emp.worklocation}</strong></p>
              </div>

              <div className="d-flex gap-2">
                <button className="btn btn-warning"
                onClick={()=> deleteEmployee(emp.id)}
                >Delete</button>
                <button className="btn btn-danger"
                onClick={()=>readytoupdate(emp)}
                >Update</button>
              </div>

            </div>

          </div>

        </div>

      ))}

      </div>

    </div>
      {showform?<div class="modal start d-block" tabindex="-1">
        <div class="modal-dialog">
            <div class="modal-content"> 
            <div class="modal-header">
                <h5 class="modal-title">Update Employee Form</h5>
                <button type="button" class="btn-close" 
                onClick={()=>{setshowform(false)}}
                data-bs-dismiss="modal" aria-label="Close"></button>
            </div>
            <div class="modal-body">
            <form onSubmit={updateemployee}>

            <h5>Personal Information</h5>

            <div className="row">

            <div className="col-md-4 mb-3">
                <label>First Name</label>
                <input type="text" 
                className="form-control" value={firstname}
                onChange={(event)=>{setfirstname(event.target.value)}}/>
            </div>

            <div className="col-md-4 mb-3">
                <label>Middle Name</label>
                <input type="text" 
                className="form-control" value={middlename}
                onChange={(event)=>{setmiddlename(event.target.value)}}/>
            </div>

            <div className="col-md-4 mb-3">
                <label>Last Name</label>
                <input type="text" 
                className="form-control" value={lastname}
                onChange={(event)=>{setlastname(event.target.value)}}/>
            </div>

            <div className="col-md-6 mb-3">
                <label>Email</label>
                <input type="email" 
                className="form-control" value={email}
                onChange={(event)=>{setemail(event.target.value)}}/>
            </div>

            <div className="col-md-6 mb-3">
                <label>Contact Number</label>
                <input type="text" 
                className="form-control" value={contactno}
                onChange={(event)=>{setcontactno(event.target.value)}}/>
            </div>

            <div className="col-md-4 mb-3">
                <label>Gender</label>
                <select className="form-control" value={gender}
                                onChange={(event)=>{setgender(event.target.value)}}>
                    <option>Select Gender</option>
                    <option>Male</option>
                    <option>Female</option>
                    </select>
            </div>

            <div className="col-md-4 mb-3">
                <label>Date of Birth</label>
                <input type="date" 
                className="form-control" value={dob}
                onChange={(event)=>{setdob(event.target.value)}}/>
            </div>

            <div className="col-md-4 mb-3">
                <label>Education</label>
            <   input type="text" className="form-control" value={edu}
                onChange={(event)=>{setedu(event.target.value)}}/>
            </div>

            <div className="col-md-6 mb-3">
                <label>Current Address</label>
                <input type="text" 
                className="form-control" value={caddress}
                onChange={(event)=>{setcaddress(event.target.value)}}/>
            </div>

            <div className="col-md-6 mb-3">
                <label>Permanent Address</label>
                <input type="text" 
                className="form-control" value={paddress}
                onChange={(event)=>{setpaddress(event.target.value)}}/>
            </div>

            <div className="col-md-6 mb-3">
                <label>Aadhar Number</label>
                <input type="text" 
                className="form-control" value={adharno}
                onChange={(event)=>{setadharno(event.target.value)}}/>
            </div>

            <div className="col-md-6 mb-3">
                <label>PAN Number</label>
                <input type="text" 
                className="form-control" value={panno}
                onChange={(event)=>{setpanno(event.target.value)}}/>
            </div>

    </div>


    <h5 className="mt-3">Work Information</h5>

    <div className="row">

        <div className="col-md-4 mb-3">
            <label>Experience</label>
            <input type="number" 
            className="form-control" value={exp}
            onChange={(event)=>{setexp(event.target.value)}}/>
        </div>

    <div className="col-md-4 mb-3">
        <label>Salary</label>
        <input type="number" 
        className="form-control" value={salary}
        onChange={(event)=>{setsalary(event.target.value)}}/>
    </div>

    <div className="col-md-4 mb-3">
    <   label>Status</label>
        <select className="form-control" value={status}
                onChange={(event)=>{setstatus(event.target.value)}}>
            <option>Select Status</option>
            <option>Active</option>
            <option>Inactive</option>
        </select>
    </div>

    <div className="col-md-4 mb-3">
        <label>Designation</label>
        <input type="text" 
        className="form-control" value={designation}
        onChange={(event)=>{setdesignation(event.target.value)}}/>
    </div>

    <div className="col-md-4 mb-3">
        <label>Department</label>
        <input type="text" 
        className="form-control" value={department}
        onChange={(event)=>{setdepartment(event.target.value)}}/>
    </div>

    <div className="col-md-4 mb-3">
        <label>Reporting Manager</label>
        <input type="text" 
        className="form-control" value={reportingmanager}
        onChange={(event)=>{setreportingmanager(event.target.value)}}/>
    </div>

    <div className="col-md-6 mb-3">
        <label>Work Location</label>
        <input type="text" 
        className="form-control" value={worklocation}
        onChange={(event)=>{setworklocation(event.target.value)}}/>
    </div>

    <div className="col-md-6 mb-3">
        <label>Joining Date</label>
        <input type="date" 
        className="form-control" value={joiningdate}
        onChange={(event)=>{setjoiningdate(event.target.value)}}/>
    </div>

</div>


    <h5 className="mt-3">Profile Image</h5>

    <div className="row">

        <div className="col-md-6 mb-3">
            <label>Upload Profile</label>
            <input type="file" accept="image/*" 
            className="form-control"
            onChange={(event)=>{handleprofile(event)}}/>
        </div>
        <div className='col-md-6 mb-3'>
            <label>Profile preview</label>
            <img src={profile}></img>
        </div>

    </div>

    <button className="btn btn-primary mt-3">Update Employee</button>

</form>
            </div>
            
            </div>
        </div>
        </div>:null}
    </div>
  )
}
